def _decode(b64: str) -> bytes:
    return base64.b64decode(b64)


@pytest.mark.parametrize("tx,b64", PNG_NEGATIVE, ids=[t[0] for t in PNG_NEGATIVE])
def test_png_damaged_falls_through_to_octet_stream(tx, b64):
    """Damaged PNGs from prod must classify as octet-stream, not image/png.

    Returning image/png here would mark these stamps valid in dev, while
    prod cursed them — a consensus break (PR #753, tx e3672c7b…).
    """
    assert classify(_decode(b64)) == "application/octet-stream", tx


@pytest.mark.parametrize("tx,b64", PNG_POSITIVE, ids=[t[0] for t in PNG_POSITIVE])
def test_png_valid_stays_image_png(tx, b64):
    assert classify(_decode(b64)) == "image/png", tx


